content.content:
1	/* ============================================
2	   今日仪表盘 - 天子日课
3	   ============================================ */
4	
5	/* ---- 日期标题 ---- */
6	.header-date {
7	  display: block;
8	  font-size: var(--text-sm);
9	  color: var(--color-text-muted);
10	  letter-spacing: 0.06em;
11	  margin-bottom: var(--space-xs);
12	}
13	
14	.header-title {
15	  display: block;
16	  font-size: var(--text-title);
17	  font-weight: 700;
18	  color: var(--color-text-primary);
19	  letter-spacing: 0.04em;
20	  line-height: 1.2;
21	}
22	
23	/* ---- 进度卡片 ---- */
24	.progress-card {
25	  background: linear-gradient(135deg, var(--color-card) 0%, #1a1612 100%);
26	  border: 1rpx solid var(--color-border);
27	  border-radius: var(--radius-xl);
28	  padding: var(--space-xl);
29	  display: flex;
30	  align-items: center;
31	  gap: var(--space-xl);
32	  margin-top: var(--space-xl);
33	  position: relative;
34	  overflow: hidden;
35	}
36	
37	.progress-card::before {
38	  content: "";
39	  position: absolute;
40	  top: 0;
41	  left: 0;
42	  right: 0;
43	  height: 2rpx;
44	  background: linear-gradient(90deg, transparent, var(--color-accent-subtle), transparent);
45	}
46	
47	.progress-ring {
48	  position: relative;
49	  width: 140rpx;
50	  height: 140rpx;
51	  flex-shrink: 0;
52	}
53	
54	.progress-pct {
55	  font-size: var(--text-lg);
56	  font-weight: 700;
57	  color: var(--color-text-primary);
58	  letter-spacing: 0.02em;
59	}
60	
61	.progress-info {
62	  display: flex;
63	  flex-direction: column;
64	  gap: var(--space-xs);
65	}
66	
67	.progress-num {
68	  font-size: var(--text-2xl);
69	  font-weight: 600;
70	  color: var(--color-text-primary);
71	  letter-spacing: 0.02em;
72	}
73	
74	.progress-label {
75	  font-size: var(--text-sm);
76	  color: var(--color-text-muted);
77	  letter-spacing: 0.04em;
78	}
79	
80	/* ---- 领域分组 ---- */
81	.domain-section {
82	  margin-top: var(--space-xl);
83	}
84	
85	.domain-title {
86	  display: block;
87	  font-size: var(--text-sm);
88	  color: var(--color-text-muted);
89	  margin-bottom: var(--space-md);
90	  letter-spacing: 0.04em;
91	  padding-left: var(--space-md);
92	  border-left: 3rpx solid var(--color-accent);
93	}
94	
95	/* ---- 习惯条目 ---- */
96	.habit-item {
97	  background: var(--color-card);
98	  border: 1rpx solid var(--color-border);
99	  border-radius: var(--radius-md);
100	  padding: var(--space-lg);
101	  margin-bottom: var(--space-sm);
102	  display: flex;
103	  align-items: center;
104	  gap: var(--space-md);
105	  transition: all 0.2s ease;
106	  position: relative;
107	  overflow: hidden;
108	}
109	
110	.habit-item:active {
111	  background: var(--color-card-hover);
112	  border-color: var(--color-border-light);
113	}
114	
115	.habit-item.done {
116	  opacity: 0.55;
117	}
118	
119	.habit-item.done::after {
120	  content: "";
121	  position: absolute;
122	  top: 0;
123	  left: 0;
124	  bottom: 0;
125	  width: 4rpx;
126	  background: var(--color-success);
127	  border-radius: 0 2rpx 2rpx 0;
128	}
129	
130	.check-icon {
131	  width: 44rpx;
132	  height: 44rpx;
133	  border-radius: var(--radius-full);
134	  border: 2rpx solid var(--color-border-light);
135	  flex-shrink: 0;
136	  display: flex;
137	  align-items: center;
138	  justify-content: center;
139	  transition: all 0.2s ease;
140	}
141	
142	.check-icon.checked {
143	  background: var(--color-accent);
144	  border-color: var(--color-accent);
145	}
146	
147	.check-icon Text {
148	  color: var(--color-text-inverse);
149	  font-size: 22rpx;
150	  font-weight: 700;
151	  line-height: 1;
152	}
153	
154	.habit-text {
155	  flex: 1;
156	  min-width: 0;
157	}
158	
159	.habit-name {
160	  display: block;
161	  font-size: var(--text-md);
162	  font-weight: 500;
163	  color: var(--color-text-primary);
164	  letter-spacing: 0.02em;
165	}
166	
167	.habit-name.done {
168	  color: var(--color-text-muted);
169	  text-decoration: line-through;
170	}
171	
172	.habit-desc {
173	  display: block;
174	  font-size: var(--text-xs);
175	  color: var(--color-text-muted);
176	  margin-top: var(--space-xs);
177	  overflow: hidden;
178	  text-overflow: ellipsis;
179	  white-space: nowrap;
180	}
181	
182	.habit-unit {
183	  font-size: var(--text-sm);
184	  color: var(--color-text-muted);
185	  flex-shrink: 0;
186	  font-feature-settings: "tnum";
187	}
188	
189	/* ============================================
190	   今日建议目标卡片
191	   ============================================ */
192	
193	.goals-card {
194	  background: linear-gradient(135deg, #1e1a15 0%, #221e1a 100%);
195	  border: 1rpx solid var(--color-border);
196	  border-left: 6rpx solid var(--color-accent);
197	  border-radius: var(--radius-lg);
198	  padding: var(--space-lg);
199	  margin-top: var(--space-lg);
200	  position: relative;
201	  overflow: hidden;
202	}
203	
204	.goals-card::before {
205	  content: "";
206	  position: absolute;
207	  top: 0;
208	  left: 6rpx;
209	  right: 0;
210	  height: 1rpx;
211	  background: linear-gradient(90deg, var(--color-accent-subtle), transparent);
212	}
213	
214	.goals-header {
215	  display: flex;
216	  align-items: center;
217	  justify-content: space-between;
218	  margin-bottom: var(--space-md);
219	}
220	
221	.goals-title {
222	  font-size: var(--text-md);
223	  font-weight: 600;
224	  color: var(--color-accent-light);
225	  letter-spacing: 0.03em;
226	}
227	
228	.goals-dismiss {
229	  width: 44rpx;
230	  height: 44rpx;
231	  border-radius: var(--radius-full);
232	  background: var(--color-surface);
233	  border: 1rpx solid var(--color-border);
234	  display: flex;
235	  align-items: center;
236	  justify-content: center;
237	  cursor: pointer;
238	  transition: background 0.2s;
239	}
240	
241	.goals-dismiss:active {
242	  background: var(--color-card-hover);
243	}
244	
245	.goals-dismiss Text {
246	  font-size: 22rpx;
247	  color: var(--color-text-muted);
248	  line-height: 1;
249	}
250	
251	/* ---- 目标条目 ---- */
252	.goals-item {
253	  background: var(--color-card);
254	  border: 1rpx solid var(--color-border);
255	  border-radius: var(--radius-md);
256	  margin-bottom: var(--space-sm);
257	  overflow: hidden;
258	  transition: border-color 0.2s;
259	}
260	
261	.goals-item:active {
262	  border-color: var(--color-accent-subtle);
263	}
264	
265	.goals-item-header {
266	  display: flex;
267	  align-items: center;
268	  justify-content: space-between;
269	  padding: var(--space-md);
270	  cursor: pointer;
271	}
272	
273	.goals-item-title {
274	  font-size: var(--text-sm);
275	  font-weight: 500;
276	  color: var(--color-text-primary);
277	  letter-spacing: 0.02em;
278	}
279	
280	.goals-item-arrow {
281	  font-size: 20rpx;
282	  color: var(--color-text-muted);
283	  transition: transform 0.2s ease;
284	}
285	
286	.goals-item-body {
287	  padding: 0 var(--space-md) var(--space-md);
288	  display: flex;
289	  flex-direction: column;
290	  gap: var(--space-sm);
291	  animation: goals-expand 0.25s ease-out;
292	}
293	
294	@keyframes goals-expand {
295	  from {
296	    opacity: 0;
297	    max-height: 0;
298	    transform: translateY(-8rpx);
299	  }
300	  to {
301	    opacity: 1;
302	    max-height: 300rpx;
303	    transform: translateY(0);
304	  }
305	}
306	
307	.goals-item-detail {
308	  display: block;
309	  font-size: var(--text-xs);
310	  color: var(--color-text-secondary);
311	  line-height: 1.7;
312	}
313	
314	.goals-item-reason {
315	  display: block;
316	  font-size: var(--text-xs);
317	  color: var(--color-accent-light);
318	  line-height: 1.6;
319	  opacity: 0.85;
320	}
321	
322	/* ---- 骨架屏 ---- */
323	.skeleton-lines {
324	  display: flex;
325	  flex-direction: column;
326	  gap: var(--space-md);
327	  padding: var(--space-sm) 0;
328	}
329	
330	.skeleton-line {
331	  height: 24rpx;
332	  border-radius: 12rpx;
333	  background: linear-gradient(
334	    90deg,
335	    var(--color-border) 25%,
336	    var(--color-border-light) 50%,
337	    var(--color-border) 75%
338	  );
339	  background-size: 200% 100%;
340	  animation: skeleton-shimmer 1.5s ease-in-out infinite;
341	}
342	
343	.skeleton-line.w-80 {
344	  width: 80%;
345	}
346	
347	.skeleton-line.w-60 {
348	  width: 60%;
349	}
350	
351	@keyframes skeleton-shimmer {
352	  0% {
353	    background-position: 200% 0;
354	  }
355	  100% {
356	    background-position: -200% 0;
357	  }
358	}
359

1	/* ============================================
2	   习惯管理 - 天子日课
3	   ============================================ */
4	
5	/* ---- 页面头部 ---- */
6	.page-header {
7	  display: flex;
8	  justify-content: space-between;
9	  align-items: flex-start;
10	  margin-bottom: var(--space-xl);
11	}
12	
13	.add-btn {
14	  width: 72rpx;
15	  height: 72rpx;
16	  border-radius: var(--radius-full);
17	  background: var(--color-accent);
18	  color: var(--color-text-inverse);
19	  display: flex;
20	  align-items: center;
21	  justify-content: center;
22	  font-size: 44rpx;
23	  font-weight: 300;
24	  line-height: 1;
25	  transition: opacity 0.2s;
26	}
27	
28	.add-btn:active {
29	  opacity: 0.8;
30	}
31	
32	/* ---- 分类管理入口 ---- */
33	.domain-manager-entry {
34	  display: flex;
35	  align-items: center;
36	  gap: var(--space-md);
37	  padding: var(--space-lg) var(--space-md);
38	  margin-bottom: var(--space-lg);
39	  background: var(--color-card);
40	  border: 1rpx solid var(--color-border);
41	  border-radius: var(--radius-lg);
42	  transition: all 0.2s;
43	}
44	
45	.domain-manager-entry:active {
46	  background: var(--color-card-hover);
47	  border-color: var(--color-border-light);
48	}
49	
50	.domain-manager-entry-bar {
51	  width: 6rpx;
52	  height: 32rpx;
53	  background: var(--color-accent);
54	  border-radius: 3rpx;
55	  flex-shrink: 0;
56	}
57	
58	.domain-manager-entry-text {
59	  flex: 1;
60	  font-size: var(--text-md);
61	  font-weight: 500;
62	  color: var(--color-text-primary);
63	  letter-spacing: 0.02em;
64	}
65	
66	.domain-manager-entry-arrow {
67	  font-size: var(--text-xl);
68	  color: var(--color-text-muted);
69	  flex-shrink: 0;
70	  line-height: 1;
71	}
72	
73	/* ---- 领域标题 ---- */
74	.domain-title {
75	  display: block;
76	  font-size: var(--text-sm);
77	  color: var(--color-text-muted);
78	  margin: var(--space-xl) 0 var(--space-md);
79	  padding-left: var(--space-md);
80	  border-left: 3rpx solid var(--color-accent);
81	}
82	
83	.domain-title-row {
84	  display: flex;
85	  align-items: center;
86	  gap: 8rpx;
87	  margin-top: 24rpx;
88	  margin-bottom: 8rpx;
89	}
90	
91	/* ---- 习惯卡片 ---- */
92	.habit-card {
93	  background: var(--color-card);
94	  border: 1rpx solid var(--color-border);
95	  border-radius: var(--radius-md);
96	  padding: var(--space-lg);
97	  margin-bottom: var(--space-sm);
98	  transition: all 0.2s ease;
99	}
100	
101	.habit-card.inactive {
102	  opacity: 0.45;
103	}
104	
105	.habit-info {
106	  margin-bottom: var(--space-md);
107	}
108	
109	.habit-name {
110	  display: block;
111	  font-size: var(--text-md);
112	  font-weight: 500;
113	  color: var(--color-text-primary);
114	  letter-spacing: 0.02em;
115	}
116	
117	.habit-desc {
118	  display: block;
119	  font-size: var(--text-xs);
120	  color: var(--color-text-muted);
121	  margin-top: var(--space-xs);
122	}
123	
124	.habit-meta {
125	  display: block;
126	  font-size: var(--text-xs);
127	  color: var(--color-text-muted);
128	  margin-top: var(--space-sm);
129	  font-feature-settings: "tnum";
130	}
131	
132	/* ---- 卡片操作按钮 ---- */
133	.habit-actions {
134	  display: flex;
135	  gap: var(--space-sm);
136	}
137	
138	.habit-actions .action-btn {
139	  padding: var(--space-xs) var(--space-md);
140	  border-radius: var(--radius-xs);
141	  font-size: var(--text-xs);
142	  font-weight: 500;
143	  background: var(--color-surface);
144	  color: var(--color-text-secondary);
145	  border: 1rpx solid var(--color-border);
146	  transition: all 0.2s;
147	}
148	
149	.habit-actions .action-btn:active {
150	  background: var(--color-border);
151	}
152	
153	.habit-actions .action-btn.danger {
154	  background: var(--color-danger-subtle);
155	  color: var(--color-danger);
156	  border-color: transparent;
157	}
158	
159	.habit-actions .action-btn.danger:active {
160	  opacity: 0.8;
161	}
162	
163	.habit-actions .action-btn.disabled {
164	  opacity: 0.4;
165	}
166	
167	/* ============================================
168	   分类管理 - 重设计
169	   ============================================ */
170	
171	/* ---- 弹窗顶饰 ---- */
172	.domain-manager-accent {
173	  width: 48rpx;
174	  height: 4rpx;
175	  background: var(--color-accent);
176	  border-radius: 2rpx;
177	  margin: 0 auto var(--space-xl);
178	  opacity: 0.6;
179	}
180	
181	/* ---- 弹窗头部 ---- */
182	.modal-header-row {
183	  display: flex;
184	  justify-content: space-between;
185	  align-items: center;
186	  margin-bottom: var(--space-xl);
187	}
188	
189	.modal-header-row .modal-title {
190	  margin-bottom: 0;
191	}
192	
193	.modal-add-btn {
194	  display: flex;
195	  align-items: center;
196	  gap: var(--space-xs);
197	  font-size: var(--text-sm);
198	  font-weight: 500;
199	  color: var(--color-accent);
200	  padding: var(--space-xs) var(--space-md);
201	  border: 1rpx solid var(--color-accent-subtle);
202	  border-radius: var(--radius-sm);
203	  background: var(--color-accent-subtle);
204	}
205	
206	/* ---- 分类列表项（卡片式） ---- */
207	.domain-item {
208	  display: flex;
209	  align-items: center;
210	  gap: var(--space-md);
211	  padding: var(--space-lg) var(--space-md);
212	  margin-bottom: var(--space-sm);
213	  background: var(--color-surface);
214	  border: 1rpx solid var(--color-border);
215	  border-radius: var(--radius-md);
216	  transition: all 0.2s;
217	}
218	
219	.domain-item:active {
220	  background: var(--color-card-hover);
221	}
222	
223	.domain-item-bar {
224	  width: 6rpx;
225	  height: 40rpx;
226	  border-radius: 3rpx;
227	  flex-shrink: 0;
228	}
229	
230	.domain-item-icon {
231	  font-size: 36rpx;
232	  flex-shrink: 0;
233	  line-height: 1;
234	}
235	
236	.domain-item-name {
237	  flex: 1;
238	  font-size: var(--text-md);
239	  color: var(--color-text-primary);
240	  font-weight: 500;
241	}
242	
243	.domain-item-tag {
244	  font-size: var(--text-xs);
245	  color: var(--color-text-muted);
246	  background: var(--color-bg);
247	  padding: var(--space-xs) var(--space-sm);
248	  border-radius: var(--radius-xs);
249	  flex-shrink: 0;
250	}
251	
252	.domain-item-actions {
253	  display: flex;
254	  gap: var(--space-sm);
255	  flex-shrink: 0;
256	}
257	
258	.domain-item-action {
259	  width: 56rpx;
260	  height: 56rpx;
261	  border-radius: var(--radius-full);
262	  display: flex;
263	  align-items: center;
264	  justify-content: center;
265	  font-size: 24rpx;
266	  transition: all 0.2s;
267	}
268	
269	.domain-item-action.edit {
270	  background: var(--color-accent-subtle);
271	  color: var(--color-accent);
272	}
273	
274	.domain-item-action.delete {
275	  background: var(--color-danger-subtle);
276	  color: var(--color-danger);
277	}
278	
279	.domain-item-action:active {
280	  transform: scale(0.88);
281	}
282	
283	.domain-item-action.disabled {
284	  opacity: 0.4;
285	}
286	
287	/* ---- 弹窗关闭按钮 ---- */
288	.domain-close-btn {
289	  display: flex;
290	  align-items: center;
291	  justify-content: center;
292	  padding: var(--space-lg) 0 var(--space-xs);
293	  font-size: var(--text-sm);
294	  color: var(--color-text-muted);
295	  letter-spacing: 0.04em;
296	  transition: color 0.2s;
297	}
298	
299	.domain-close-btn:active {
300	  color: var(--color-text-secondary);
301	}
302	
303	/* ---- 表单区块 ---- */
304	.form-section {
305	  margin-bottom: var(--space-xl);
306	}
307	
308	.form-section-title {
309	  display: block;
310	  font-size: var(--text-sm);
311	  font-weight: 500;
312	  color: var(--color-text-secondary);
313	  margin-bottom: var(--space-md);
314	  letter-spacing: 0.02em;
315	}
316	
317	/* ---- Emoji 选择器（双行横滚） ---- */
318	.emoji-picker-rows {
319	  display: flex;
320	  flex-direction: column;
321	  gap: var(--space-sm);
322	}
323	
324	.emoji-row {
325	  display: flex;
326	  gap: var(--space-sm);
327	  overflow-x: auto;
328	  overflow-y: hidden;
329	  padding: var(--space-xs) 0;
330	  -webkit-overflow-scrolling: touch;
331	  scrollbar-width: none;
332	}
333	
334	.emoji-row::-webkit-scrollbar {
335	  display: none;
336	}
337	
338	.emoji-pill {
339	  width: 76rpx;
340	  height: 76rpx;
341	  border-radius: var(--radius-md);
342	  background: var(--color-surface);
343	  border: 1.5rpx solid var(--color-border);
344	  display: flex;
345	  align-items: center;
346	  justify-content: center;
347	  font-size: 34rpx;
348	  flex-shrink: 0;
349	  transition: all 0.2s;
350	  box-sizing: border-box;
351	}
352	
353	.emoji-pill:active {
354	  transform: scale(0.92);
355	  border-color: var(--color-accent);
356	}
357	
358	.emoji-pill.selected {
359	  background: var(--color-accent-subtle);
360	  border-color: var(--color-accent);
361	  transform: scale(1.08);
362	}
363	
364	/* ---- SVG 图标选择器 ---- */
365	.icon-picker-grid {
366	  display: flex;
367	  flex-direction: column;
368	  gap: var(--space-sm);
369	}
370	
371	.icon-pill {
372	  width: 76rpx;
373	  height: 76rpx;
374	  border-radius: var(--radius-md);
375	  background: var(--color-surface);
376	  border: 2rpx solid transparent;
377	  display: flex;
378	  align-items: center;
379	  justify-content: center;
380	  flex-shrink: 0;
381	  transition: all 0.2s;
382	  box-sizing: border-box;
383	}
384	
385	.icon-pill:active {
386	  transform: scale(0.92);
387	  border-color: var(--color-accent);
388	}
389	
390	.icon-pill.selected {
391	  border-color: var(--color-accent);
392	  transform: scale(1.08);
